async function onion(ctx: any, middlewares: Function[]) {
    let index = -1;
    async function dispatch(i: number) {
        if (i <= index) throw new Error('next() called multiple times');
        index = i;
        const fn = middlewares[i];
        if (fn) await fn(ctx, () => dispatch(i + 1));
    }
    await dispatch(0);
}

