interface KnowledgeRepository {
    addDocument(doc: Document): Promise<string>;
    search(query: string, limit: number): Promise<Document[]>;
    getDocument(id: string): Promise<Document | null>;
}

class VectorKnowledgeRepo implements KnowledgeRepository {
    private docs: Map<string, Document> = new Map();

    async addDocument(doc: Document) {
        const id = crypto.randomUUID();
        doc.embedding = await this.getEmbedding(doc.content);
        this.docs.set(id, doc);
        return id;
    }

    async search(query: string, limit: number) {
        const queryEmbed = await this.getEmbedding(query);
        return [...this.docs.values()]
            .map(d => ({ doc: d, score: this.cosine(d.embedding, queryEmbed) }))
            .sort((a, b) => b.score - a.score)
            .slice(0, limit)
            .map(r => r.doc);
    }
}

type Step<T> = (data: T) => T;

class Pipeline<T> {
    private steps: Step<T>[] = [];

    pipe(step: Step<T>) {
        this.steps.push(step);
        return this;
    }

    execute(data: T): T {
        return this.steps.reduce((acc, step) => step(acc), data);
